INSERT INTO `machines` (`id`, `name`, `kana`, `overview`, `code`, `abbreviation`, `manufacturer_id`, `machine_type`, `release_date`, `sort_order`, `created_at`, `updated_at`) VALUES (1, 'ファミリーコンピュータ', 'ファミリーコンピュータ', 'ファミリーコンピュータは、任天堂が1983年に発売した家庭用ゲーム機です。略称は「ファミコン」とも呼ばれます。当時の家庭用ゲーム機としては、画面のグラフィック性能が高く、シンプルなコントローラーも親しまれました。また、ゲームソフトウェアの多彩なラインナップや、後に登場した外付けディスクシステムを使ったゲームのダウンロードも人気を集めました。ファミリーコンピュータは、アーケードゲームから移植された作品や、任天堂自社開発の作品など、多くのゲームを発売し、日本だけでなく世界中で広く愛されるゲーム機となりました。現在でも、多くの人にとって思い出深いゲーム機として語り継がれています。', 'FC', 'FC', 1, 'STATIONARY', '1993-07-15', 1, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `machines` (`id`, `name`, `kana`, `overview`, `code`, `abbreviation`, `manufacturer_id`, `machine_type`, `release_date`, `sort_order`, `created_at`, `updated_at`) VALUES (2, 'ディスクシステム', 'ディスクシステム', 'ディスクシステムは、任天堂が1986年に発売したファミリーコンピュータの周辺機器です。ゲームソフトを磁気ディスクに保存し、ファミリーコンピュータに接続することでゲームをプレイできるようになります。ディスクシステムを使うことで、メモリーカートリッジに比べて大容量のデータを扱うことができ、ゲームの保存や、新しいゲームのダウンロードも可能となりました。また、ディスクシステムには、音声や音楽などの追加データを収録したゲームソフトも発売され、よりリッチなゲーム体験を提供しました。しかし、ディスクの信頼性が低く、耐久性に問題があったため、ファミリーコンピュータの普及後期にはあまり採用されず、現在ではレアなアイテムとなっています。', 'FCD', 'FCD', 1, 'STATIONARY', '1986-02-21', 2, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `machines` (`id`, `name`, `kana`, `overview`, `code`, `abbreviation`, `manufacturer_id`, `machine_type`, `release_date`, `sort_order`, `created_at`, `updated_at`) VALUES (3, 'スーパーファミコン', 'スーパーファミコン', 'スーパーファミコンは、任天堂が1990年に発売した家庭用ゲーム機です。略称は「スーファミ」とも呼ばれます。ファミリーコンピュータに比べ、グラフィック性能や音声性能が向上し、新しい操作性を追求したコントローラーも登場しました。多彩なゲームソフトが発売され、RPGやアクションなど、多様なジャンルが展開されました。また、後に発売された周辺機器「スーパーファミコンアーカイブス」を使って、ファミリーコンピュータのゲームソフトもプレイ可能となりました。スーパーファミコンは、日本だけでなく世界中で人気を博し、多くの人にとって、思い出深いゲーム機のひとつとなっています。', 'SFC', 'SFC', 1, 'STATIONARY', '1990-11-21', 3, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `machines` (`id`, `name`, `kana`, `overview`, `code`, `abbreviation`, `manufacturer_id`, `machine_type`, `release_date`, `sort_order`, `created_at`, `updated_at`) VALUES (4, 'ニンテンドー64', 'ニンテンドーロクジュウヨン', 'ニンテンドー64は、任天堂が1996年に発売した家庭用ゲーム機です。世界初の64ビットCPUを搭載し、より高画質かつリアルな3Dグラフィックスを実現しました。また、カートリッジ形式のゲームソフトは、CD-ROMよりも高速な読み込みが可能であり、ロード時間が少ないことも特徴的です。ニンテンドー64は、マリオシリーズやゼルダの伝説シリーズ、スターウォーズシリーズなどの大作タイトルが多数発売され、多くのゲームファンに愛されました。また、4つのコントローラーポートを搭載しており、4人まで同時にプレイ可能なマルチプレイ機能も人気を集めました。しかし、ゲームソフトの価格が高かったことや、CD-ROM形式のプレイステーションに対して劣勢だったことなどから、販売台数はそれほど伸びず、次世代機種であるニンテンドーゲームキューブに移行しました。', 'N64', 'N64', 1, 'STATIONARY', '1996-06-23', 4, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `machines` (`id`, `name`, `kana`, `overview`, `code`, `abbreviation`, `manufacturer_id`, `machine_type`, `release_date`, `sort_order`, `created_at`, `updated_at`) VALUES (5, 'Wii', 'ウィー', 'Wiiは、任天堂が2006年に発売した家庭用ゲーム機です。従来のゲーム機とは異なり、モーションセンサーを搭載したコントローラーを使用し、身体を動かすことでゲームを操作することができます。この画期的な操作方法が評価され、幅広い年齢層から支持されました。また、ニンテンドーDSのタッチパネルにも対応しており、新しい操作方法を採用したゲームが多数発売されました。さらに、バーチャルコンソールやWiiウェアなどのダウンロードゲームも展開され、多様なコンテンツが楽しめるようになりました。Wiiは、発売から数年間で世界中で1億台以上の販売台数を記録し、任天堂にとって大きな成功を収めたゲーム機のひとつとなりました。', 'Wii', 'Wii', 1, 'STATIONARY', '2006-12-02', 6, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `machines` (`id`, `name`, `kana`, `overview`, `code`, `abbreviation`, `manufacturer_id`, `machine_type`, `release_date`, `sort_order`, `created_at`, `updated_at`) VALUES (6, 'WiiU', 'ウィーユー', 'Wii Uは、任天堂が2012年に発売した家庭用ゲーム機です。従来のWiiと同様に、モーションセンサーを搭載したコントローラーを使用し、身体を動かすことでゲームを操作することができます。しかし、Wii Uは従来のゲーム機に比べ、高性能なグラフィックや、タッチスクリーン機能を搭載したコントローラーなど、新しい要素を取り入れています。また、コントローラーと本体を接続することで、画面を二分割して遊ぶことができる「Wii U GamePad」機能も特徴的です。Wii Uは、ゼルダの伝説やスーパーマリオブラザーズ、マリオカート8などの人気タイトルが発売され、一定の支持を得ました。しかし、販売台数はWiiに比べ伸び悩み、2017年に販売終了となりました。', 'WiiU', 'WiiU', 1, 'STATIONARY', '2012-12-08', 7, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `machines` (`id`, `name`, `kana`, `overview`, `code`, `abbreviation`, `manufacturer_id`, `machine_type`, `release_date`, `sort_order`, `created_at`, `updated_at`) VALUES (7, 'Nintendo Switch', 'ニンテンドースイッチ', 'Nintendo Switchは、任天堂が2017年に発売した家庭用ゲーム機です。携帯モード、テレビモード、卓上モードの3つのプレイスタイルが可能で、どこでも手軽に楽しめる点が特徴です。Joy-Conと呼ばれるコントローラーは、左右に分かれており、それぞれが独立して遊べる「ジョイコン分割プレイ」にも対応しています。また、複数人で遊ぶことができるマルチプレイにも力を入れており、Joy-Conを渡し合って遊ぶ「ジョイコン共有プレイ」も可能です。Nintendo Switchは、マリオ、ゼルダ、ポケモンなどの任天堂の看板タイトルをはじめ、様々なゲームが発売され、ハードとソフトの相乗効果で大きな成功を収めました。2021年9月時点での累計販売台数は1億台を超えています。', 'switch', 'switch', 1, 'BOTH', '2017-03-03', 8, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `machines` (`id`, `name`, `kana`, `overview`, `code`, `abbreviation`, `manufacturer_id`, `machine_type`, `release_date`, `sort_order`, `created_at`, `updated_at`) VALUES (8, 'PlayStation', 'プレイステーション', 'プレイステーションは、ソニーが1994年に発売した家庭用ゲーム機です。CD-ROMを採用し、従来のカートリッジ方式に比べ、より多くのデータを読み込むことができる点が特徴的でした。グラフィックやサウンドの品質も大幅に向上し、当時の他の家庭用ゲーム機に比べ、高い性能を誇っていました。プレイステーションは、ファイナルファンタジーシリーズやバイオハザードシリーズなど、多くの人気タイトルが発売され、大きな成功を収めました。また、後に発売された小型版の「PSone」も好評でした。プレイステーションは、その後のプレイステーションシリーズの基盤を築き、現在のゲーム業界に大きな影響を与えました。', 'PS', 'PS', 2, 'STATIONARY', '1994-12-03', 9, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `machines` (`id`, `name`, `kana`, `overview`, `code`, `abbreviation`, `manufacturer_id`, `machine_type`, `release_date`, `sort_order`, `created_at`, `updated_at`) VALUES (9, 'PlayStation2', 'プレイステーションツー', 'プレイステーション2は、2000年にソニーが発売した家庭用ゲーム機です。DVD-ROMを採用したことにより、初代プレイステーションよりも高精細なグラフィックや大容量のデータを扱えるようになり、多くのゲームメーカーが3Dグラフィックスに力を入れた作品を開発しました。また、オンラインプレイにも対応し、ネットワークゲームの発展に大きく貢献しました。PS2は、多くの優れたタイトルが発売され、世界中で高い評価を受け、累計販売台数は1億1, 500万台を超えています。今でも愛され続け、一部のタイトルが再発売されるなど、ゲーム業界に大きな影響を与えています。', 'PS2', 'PS2', 2, 'STATIONARY', '2000-03-04', 10, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `machines` (`id`, `name`, `kana`, `overview`, `code`, `abbreviation`, `manufacturer_id`, `machine_type`, `release_date`, `sort_order`, `created_at`, `updated_at`) VALUES (10, 'PlayStation3', 'プレイステーションスリー', 'プレイステーション3は、2006年にソニーが発売した家庭用ゲーム機です。Blu-rayディスクを採用し、高品質な映像や音声を楽しめることが特徴でした。また、PlayStation Networkによるオンラインサービスや、PlayStation Moveによるモーションコントロールに対応しており、新たなゲームプレイ体験を提供しました。しかし、初期の販売価格が高く、ソフトウェアラインナップも充実しなかったことなどから、発売当初は苦戦しました。しかし、後に発売されたモデルの価格改定や、人気タイトルの発売により、徐々に販売台数を伸ばし、累計販売台数は8, 000万台を超えています。', 'PS3', 'PS3', 2, 'STATIONARY', '2006-11-11', 11, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `machines` (`id`, `name`, `kana`, `overview`, `code`, `abbreviation`, `manufacturer_id`, `machine_type`, `release_date`, `sort_order`, `created_at`, `updated_at`) VALUES (11, 'PlayStation4', 'プレイステーションフォー', 'プレイステーション4は、2013年にソニーが発売した家庭用ゲーム機です。AMD製のカスタムAPUを採用し、高い処理能力と豊富なメモリを備え、高画質で快適なゲームプレイを提供しました。また、ハードウェアによる動画キャプチャーやストリーミング機能、シェアプレイなどのソーシャル機能も充実しています。さらに、PlayStation VRという仮想現実のヘッドマウントディスプレイに対応することで、新しいゲーム体験を提供しました。販売開始から約7年間で累計販売台数は1億台以上に達し、高い評価を得ています。', 'PS4', 'PS4', 2, 'STATIONARY', '2014-02-22', 12, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `machines` (`id`, `name`, `kana`, `overview`, `code`, `abbreviation`, `manufacturer_id`, `machine_type`, `release_date`, `sort_order`, `created_at`, `updated_at`) VALUES (12, 'PlayStation5', 'プレイステーションファイブ', 'プレイステーション5は、2020年にソニーが発売した次世代家庭用ゲーム機です。AMD製のカスタムAPUを搭載し、高速なSSDによる読み込み速度の向上やレイトレーシングによる高品質なグラフィックスなど、高い処理性能と画質を提供します。また、新しいコントローラー「DualSense」では、タッチパッドやモーションセンサーなどの機能に加え、振動機能による没入感の向上を図っています。さらに、PlayStation Plusに加入することで、毎月のフリーゲームやマルチプレイヤーに参加することが可能です。世界中で大きな話題となり、高い人気を誇っています。', 'PS5', 'PS5', 9, 'STATIONARY', '2020-11-12', 13, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `machines` (`id`, `name`, `kana`, `overview`, `code`, `abbreviation`, `manufacturer_id`, `machine_type`, `release_date`, `sort_order`, `created_at`, `updated_at`) VALUES (13, 'Xbox', 'エックスボックス', 'Xboxは、2001年にマイクロソフトが発売した家庭用ゲーム機です。インテル製のCPUを搭載し、高品質なグラフィックスや音声を提供することができました。また、標準でハードディスクを搭載しており、大容量のデータを保存することができた点が特徴的です。多くの人気タイトルを発売し、その中でも「Halo: Combat Evolved」は特に有名で、Xboxの代表的なゲームとなりました。さらに、オンラインマルチプレイヤーゲームの普及にも貢献し、Xbox Liveサービスを提供することで、世界中のユーザーがオンラインでプレイできるようになりました。', 'Xbox', 'Xbox', 3, 'STATIONARY', '2002-02-22', 14, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `machines` (`id`, `name`, `kana`, `overview`, `code`, `abbreviation`, `manufacturer_id`, `machine_type`, `release_date`, `sort_order`, `created_at`, `updated_at`) VALUES (14, 'XBox360', 'エックスボックスサンロクマル', 'Xbox 360は、マイクロソフトが2005年に発売した家庭用ゲーム機です。PowerPCベースのCPUと高性能なグラフィックスを搭載し、リアルな映像表現や高度なゲームプレイを提供しました。また、Xbox Liveサービスを標準装備し、オンラインマルチプレイヤーゲームをさらに発展させました。大ヒット作としては、「Halo 3」や「Gears of War」などがあり、多くのユーザーから支持を得ました。さらに、Kinectというモーションセンサーを導入し、コントローラーを使わずにゲームをプレイすることができるようになりました。', 'Xb360', 'Xb360', 3, 'STATIONARY', '2005-12-10', 15, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `machines` (`id`, `name`, `kana`, `overview`, `code`, `abbreviation`, `manufacturer_id`, `machine_type`, `release_date`, `sort_order`, `created_at`, `updated_at`) VALUES (15, 'Xbox One', 'エックスボックスワン', 'Xbox Oneは、マイクロソフトが2013年に発売した家庭用ゲーム機です。x86アーキテクチャのCPUと高性能なグラフィックスを搭載し、リアルな映像表現や高度なゲームプレイを提供しました。また、Xbox Liveサービスを標準装備し、オンラインマルチプレイヤーゲームを楽しめます。新機能としては、Kinectの改良や、スマートフォンやタブレットとの連携が挙げられます。また、Xbox One Sというモデルでは、よりコンパクトなサイズや、HDRに対応するなどの進化を遂げました。2020年には、Xbox Oneの後継機種である「Xbox Series X/S」が発売され、性能面やゲーム体験の向上が期待されています。', 'One', 'One', 3, 'STATIONARY', '2014-09-04', 16, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `machines` (`id`, `name`, `kana`, `overview`, `code`, `abbreviation`, `manufacturer_id`, `machine_type`, `release_date`, `sort_order`, `created_at`, `updated_at`) VALUES (16, 'Xbox Series X/S', 'エックスボックスシリーズエックスエス', 'Xbox Series X/Sは、マイクロソフトが2020年に発売した次世代家庭用ゲーム機です。Xbox Oneと比較して、CPUやGPU、ストレージなどの性能が大幅に向上し、高速でスムーズなゲームプレイを実現しています。また、4K解像度やHDR、120fpsなど、より高画質で臨場感のあるゲーム体験が可能です。Xbox Game PassやEA Playなどのサブスクリプションサービスにも対応し、大量のゲームを低価格で楽しめます。さらに、Xbox Series X/Sは、PCとのクロスプラットフォームプレイを実現し、さまざまなプラットフォームでプレイすることができます。', 'XSX', 'XSX', 3, 'STATIONARY', '2020-11-11', 17, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `machines` (`id`, `name`, `kana`, `overview`, `code`, `abbreviation`, `manufacturer_id`, `machine_type`, `release_date`, `sort_order`, `created_at`, `updated_at`) VALUES (17, 'メガドライブ', 'メガドライブ', 'メガドライブは、セガ社が1988年に発売した家庭用ゲーム機です。当時のゲーム機市場では、任天堂のファミリーコンピュータが主流でしたが、メガドライブは16ビットCPUを搭載しており、より高精細なグラフィックとサウンドを実現しました。また、カートリッジ交換式のゲームソフトウェアに対応しており、スポーツゲームやアクションゲーム、RPGなどの多彩なゲームがリリースされました。日本だけでなく、欧米やブラジルでも人気を博し、セガの代表的なハードウェアのひとつとなりました。メガドライブは後継機種の発売やリバイバル版の販売などを通じ、今でも多くのファンに愛され続けています。', 'MD', 'MD', 4, 'STATIONARY', '1988-10-29', 18, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `machines` (`id`, `name`, `kana`, `overview`, `code`, `abbreviation`, `manufacturer_id`, `machine_type`, `release_date`, `sort_order`, `created_at`, `updated_at`) VALUES (18, 'セガサターン', 'セガサターン', 'セガサターンは、1994年にセガから発売された家庭用ゲーム機です。初めてCD-ROMを採用し、3Dポリゴン表示機能やハードウェアによるアフィン変換など、当時としては高度なグラフィック機能を持っていました。また、ゲーム開発者向けに高度な開発環境が用意され、多数の優れた作品が生まれました。しかし、PlayStationやNintendo 64などのライバル機に比べて販売台数が伸び悩み、セガのゲーム機市場からの撤退につながりました。しかし、現在でも熱烈なファンがおり、レトロゲームとして愛されています。', 'SS', 'SS', 4, 'STATIONARY', '1994-11-22', 19, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `machines` (`id`, `name`, `kana`, `overview`, `code`, `abbreviation`, `manufacturer_id`, `machine_type`, `release_date`, `sort_order`, `created_at`, `updated_at`) VALUES (19, 'ドリームキャスト', 'ドリームキャスト', 'ドリームキャストは、1998年にセガが発売した家庭用ゲーム機です。当時の最新技術を搭載し、オンラインゲームにも対応していました。特に、VMUと呼ばれるメモリーカードに小型LCD画面を搭載し、ゲーム中にキャラクターの成長やアイテムの管理などができるなど、先進的な機能が多く採用されていました。しかし、プレイステーション2など他のゲーム機との競争に敗れ、2001年に生産が終了しました。それでも、多くのファンに愛され、今でも愛好家によってプレイされています。', 'DC', 'DC', 4, 'STATIONARY', '1998-11-27', 20, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `machines` (`id`, `name`, `kana`, `overview`, `code`, `abbreviation`, `manufacturer_id`, `machine_type`, `release_date`, `sort_order`, `created_at`, `updated_at`) VALUES (20, 'PCエンジン', 'ピーシーエンジン', 'PCエンジンは、1987年に日本のナムコ（後のバンダイナムコゲームス）とNECが共同開発した家庭用ゲーム機です。ハードウェア性能が高く、当時の他のゲーム機よりも優れたグラフィックスとサウンドを実現しました。また、カード型のゲームメディアを採用し、携帯性にも優れていました。PCエンジンは、シューティングゲームやアクションゲーム、ロールプレイングゲームなど、多彩なジャンルのゲームがリリースされ、日本だけでなくアメリカやヨーロッパでも人気を博しました。しかし、後発のスーパーファミコンやメガドライブに比べて市場シェアが低く、1994年に生産が終了しました。しかし、今でも多くのファンに愛され、リバイバル商品や復刻版がリリースされています', 'PCE', 'PCE', 5, 'STATIONARY', '1987-10-30', 21, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `machines` (`id`, `name`, `kana`, `overview`, `code`, `abbreviation`, `manufacturer_id`, `machine_type`, `release_date`, `sort_order`, `created_at`, `updated_at`) VALUES (21, 'ネオジオ（ROM）', 'ネオジオ（ロム）', 'ネオジオは、1990年代にSNKが発売したアーケードゲーム機と家庭用ゲーム機のシリーズ名です。当時のアーケードゲーム機に比べて、高度なグラフィックスとサウンドを実現していました。また、ゲームカセットを使用していたため、容量が大きく、高品質なグラフィックスと音楽を実現できました。そのため、多くのジャンルのゲームがリリースされ、世界中で人気を博しました。1990年代後半には、ネオジオCDやネオジオポケットといった派生機種も登場しました。しかし、高価な価格とカセット型メディアの独自性が災いし、販売不振に陥り、2001年に生産を終了しました。それでも、多くのファンから支持され、今でもネオジオのゲームはリバイバル商品や復刻版が発売されています。', 'NG', 'NG', 6, 'STATIONARY', '1990-04-26', 22, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `machines` (`id`, `name`, `kana`, `overview`, `code`, `abbreviation`, `manufacturer_id`, `machine_type`, `release_date`, `sort_order`, `created_at`, `updated_at`) VALUES (22, '3DO', 'スリーディーオー', '3DOは、1993年に発売された家庭用ゲーム機です。当時、米国のテクノロジー企業である3DO社が設計し、世界各地の電子機器メーカーによって製造・販売されました。高度なグラフィックスやCD-ROMを採用し、多彩なジャンルのゲームがリリースされ、期待されましたが、高価格や他の競合ゲーム機との価格競争に敗れ、販売不振に陥りました。そのため、短い期間で生産が終了しました。それでも、多彩なゲームや独特なハードウェア仕様が、多くのファンに愛され続けています。また、3DO社の技術革新によって、後にリリースされたゲーム機に影響を与えたことも注目されています。', '3DO', '3DO', 7, 'STATIONARY', '1994-03-20', 23, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `machines` (`id`, `name`, `kana`, `overview`, `code`, `abbreviation`, `manufacturer_id`, `machine_type`, `release_date`, `sort_order`, `created_at`, `updated_at`) VALUES (23, 'PC-FX', 'ピーシーエフエックス', 'PC-FXは、1994年に日本のNECが発売した家庭用ゲーム機です。3DOやセガサターンなどの競合製品に対抗するために開発されました。高度なグラフィックスとCD-ROMを採用し、アニメーションなどの映像作品に特化しており、多くのアニメーションゲームがリリースされました。また、音源にはCD音源を使用し、高品質なサウンドを実現していました。しかし、高価格や市場の縮小によって販売不振に陥り、生産期間はわずか2年で終了しました。それでも、アニメーション好きやレトロゲームファンには根強い人気を誇っています。', 'PCFX', 'PCFX', 5, 'STATIONARY', '1994-12-23', 24, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `machines` (`id`, `name`, `kana`, `overview`, `code`, `abbreviation`, `manufacturer_id`, `machine_type`, `release_date`, `sort_order`, `created_at`, `updated_at`) VALUES (24, 'ゲームボーイ', 'ゲームボーイ', 'ゲームボーイは、任天堂が1989年に発売した携帯型ゲーム機です。モノクロの液晶ディスプレイと交換可能なカートリッジを採用し、軽量かつ低価格でありながら、多彩なゲームが楽しめました。また、長時間のプレイが可能な省電力設計と、液晶画面の可視角度の広さが特徴的でした。後に発売されたバージョンには、カラー液晶を採用した「ゲームボーイカラー」と、背面ライトを追加した「ゲームボーイアドバンスSP」があります。ゲームボーイは、その広大なゲームライブラリーと堅牢性の高さから、レトロゲームファンに愛され続け、今でも多くの人々がプレイしています。', 'GB', 'GB', 1, 'PORTABLE', '1989-04-21', 25, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `machines` (`id`, `name`, `kana`, `overview`, `code`, `abbreviation`, `manufacturer_id`, `machine_type`, `release_date`, `sort_order`, `created_at`, `updated_at`) VALUES (25, 'ゲームボーイアドバンス', 'ゲームボーイアドバンス', 'ゲームボーイアドバンスは、任天堂が2001年に発売した携帯型ゲーム機です。32ビットのCPUを搭載し、ハイクオリティなグラフィックスやサウンドを実現しました。また、バックライト機能を搭載し、より明るく鮮やかな画面を楽しめるようになりました。カートリッジ形式でのゲームメディアを採用し、ゲームボーイ/ゲームボーイカラー用のソフトもプレイ可能でした。その後、バージョンアップされた「ゲームボーイアドバンスSP」や「ゲームボーイミクロ」が発売されました。ゲームボーイアドバンスは、その豊富なラインナップと高性能なハードウェアによって、レトロゲームファンに人気があり、今でも多くの人々に愛され続けています。', 'GBA', 'GBA', 1, 'PORTABLE', '2001-03-21', 26, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `machines` (`id`, `name`, `kana`, `overview`, `code`, `abbreviation`, `manufacturer_id`, `machine_type`, `release_date`, `sort_order`, `created_at`, `updated_at`) VALUES (26, 'ニンテンドーDS', 'ニンテンドーディーエス', 'ニンテンドーDSは、任天堂が2004年に発売した携帯型ゲーム機です。ダブルスクリーンとタッチパネルを採用し、新しいゲームプレイの可能性を広げました。その後、マイクやカメラなどの機能が追加されたバージョンも発売されました。また、Wi-Fi機能を搭載し、インターネットを介して他のプレイヤーと対戦したり、コミュニケーションを取ったりすることができました。豊富なゲームライブラリーと、独自のハードウェアによる革新的なゲームプレイが話題となり、多くの人々から愛されました。ニンテンドーDSは、その後も改良型の「ニンテンドーDS Lite」や「ニンテンドーDSi」が発売され、今でもレトロゲームファンに人気があります。', 'DS', 'DS', 1, 'PORTABLE', '2004-12-02', 27, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `machines` (`id`, `name`, `kana`, `overview`, `code`, `abbreviation`, `manufacturer_id`, `machine_type`, `release_date`, `sort_order`, `created_at`, `updated_at`) VALUES (27, 'ニンテンドー3DS', 'ニンテンドースリーディーエス', 'ニンテンドー3DSは、任天堂が2011年に発売した携帯型ゲーム機です。3D画面とタッチパネルを搭載し、新しいゲームプレイの可能性を広げました。また、カメラやジャイロセンサーなど、様々な機能を備えており、現実世界と仮想世界をつなぐ様々なコンテンツを楽しむことができました。また、Wi-Fi機能やストリートパス機能を搭載し、他のプレイヤーとの交流も盛んでした。後に、改良型の「ニンテンドー3DS LL/XL」や「ニンテンドー2DS」が発売されました。ニンテンドー3DSは、豊富なゲームライブラリーや独自のハードウェアによる革新的なゲームプレイが話題となり、多くの人々から愛されました。', '3DS', '3DS', 1, 'PORTABLE', '2011-02-26', 28, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `machines` (`id`, `name`, `kana`, `overview`, `code`, `abbreviation`, `manufacturer_id`, `machine_type`, `release_date`, `sort_order`, `created_at`, `updated_at`) VALUES (28, 'PlayStation Portable', 'プレイステーションポータブル', 'PlayStation Portable（PSP）は、ソニー・コンピュータエンタテインメントが2004年に発売した携帯型ゲーム機です。UMDディスクやメモリースティックなどのメディアを使用し、豊富なゲームライブラリーを楽しむことができました。また、音楽や動画再生機能、インターネットブラウザーなど、多様な機能を搭載しており、ポータブルエンターテインメントマシンとしても人気を博しました。後に、Wi-Fi機能やカメラ、マイクなどの機能を搭載した改良型のPSPシリーズも発売されました。PSPは、その高性能なグラフィックスやハードウェアによる革新的なゲームプレイが話題となり、多くの人々から愛されました。', 'PSP', 'PSP', 2, 'PORTABLE', '2004-12-12', 29, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `machines` (`id`, `name`, `kana`, `overview`, `code`, `abbreviation`, `manufacturer_id`, `machine_type`, `release_date`, `sort_order`, `created_at`, `updated_at`) VALUES (29, 'PlayStation Vita', 'プレイステーションヴィータ', 'PlayStation Vitaは、ソニー・コンピュータエンタテインメントが2011年に発売した携帯型ゲーム機です。5インチのOLEDディスプレイとタッチパッドを搭載し、高性能なグラフィックスと多彩な操作性を実現しました。また、前面・背面にカメラやWi-Fi機能、GPS機能、モーションセンサーなど、多様な機能を搭載しており、ポータブルエンターテインメントマシンとしての機能も充実していました。PlayStation Vitaは、豊富なゲームライブラリーや、PlayStation 4との連携機能などが話題となり、多くの人々から愛されましたが、市場での競争力不足などの要因により、2019年に生産が終了しています。', 'VITA', 'VITA', 2, 'PORTABLE', '2011-12-17', 30, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `machines` (`id`, `name`, `kana`, `overview`, `code`, `abbreviation`, `manufacturer_id`, `machine_type`, `release_date`, `sort_order`, `created_at`, `updated_at`) VALUES (30, 'ゲームギア', 'ゲームギア', 'ゲームギアは、セガが1990年代に発売した携帯型ゲーム機です。カラー液晶ディスプレイを搭載しており、当時としては画期的なグラフィック性能を誇りました。また、TVチューナーやカートリッジスロット、外部電源端子などの拡張性も高く、豊富な周辺機器も発売されました。しかし、高価な値段や電池の消費が激しいなど、一部のユーザーからのみ支持され、メガドライブに比べて販売数は伸びませんでした。その後も改良型のゲームギアシリーズが発売されましたが、2000年に生産が終了しました。最近では、セガが2020年に発売した「ゲームギアミクロ」で復刻され、一部のファンから注目を集めています。', 'GG', 'GG', 4, 'PORTABLE', '1990-10-06', 31, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `machines` (`id`, `name`, `kana`, `overview`, `code`, `abbreviation`, `manufacturer_id`, `machine_type`, `release_date`, `sort_order`, `created_at`, `updated_at`) VALUES (31, 'ネオジオポケット', 'ネオジオポケット', 'ネオジオポケットは、SNKが1998年に発売した携帯型ゲーム機です。16ビットCPUと160x152ピクセルのモノクロ液晶を搭載し、軽量・コンパクトなボディに多彩な操作ボタンを備え、高い携帯性と快適なゲームプレイを実現しました。また、ゲームカード交換式のスロットを備え、多くのタイトルが発売され、携帯型ゲーム機としての存在感を示しました。しかし、激しいゲーム市場競争や、ゲームボーイカラーの台頭などの要因により、販売不振に陥り、短い期間で生産終了となりました。その後、ネオジオポケットカラーが発売されたものの、2001年に生産終了しました。', 'NGP', 'NGP', 6, 'PORTABLE', '1998-10-28', 32, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `machines` (`id`, `name`, `kana`, `overview`, `code`, `abbreviation`, `manufacturer_id`, `machine_type`, `release_date`, `sort_order`, `created_at`, `updated_at`) VALUES (32, 'ネオジオポケットカラー', 'ネオジオポケットカラー', 'ネオジオポケットカラーは、SNKが1999年に発売した携帯型ゲーム機で、ネオジオポケットのカラー版として登場しました。当時としては高精細な160x152ピクセルのカラー液晶を搭載し、同時期に発売されたゲームボーイカラーに対抗するためにカラー対応のタイトルを多数展開しました。携帯性に優れ、大量のゲームタイトルが発売され、ゲームファンからも支持されましたが、競合機種の中でも販売数が伸び悩み、2001年に生産終了となりました。現在では、一部のファンやコレクターから高い人気を誇っています。', 'NGPC', 'NGPC', 6, 'PORTABLE', '1999-03-19', 33, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `machines` (`id`, `name`, `kana`, `overview`, `code`, `abbreviation`, `manufacturer_id`, `machine_type`, `release_date`, `sort_order`, `created_at`, `updated_at`) VALUES (33, 'ワンダースワン', 'ワンダースワン', 'ワンダースワンは、1999年にバンダイが発売した携帯型ゲーム機で、モノクロ液晶を採用した初代モデルと、後にカラー液晶を採用した「ワンダースワンカラー」があります。コンパクトなサイズで、単4電池2本で動作し、携帯性に優れていました。様々なジャンルのタイトルが発売され、特に「フロントミッション」や「サモンナイト」などの人気シリーズが展開されました。しかし、PlayStation PortableやニンテンドーDSなどの携帯型ゲーム機に市場を奪われ、2003年に生産終了となりました。現在でも一部のファンからは高い評価を受けており、コレクターズアイテムとしても人気があります。', 'WS', 'WS', 8, 'PORTABLE', '1999-03-04', 34, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `machines` (`id`, `name`, `kana`, `overview`, `code`, `abbreviation`, `manufacturer_id`, `machine_type`, `release_date`, `sort_order`, `created_at`, `updated_at`) VALUES (34, 'ワンダースワンカラー', 'ワンダースワンカラー', 'ワンダースワンカラーは、2000年にバンダイが発売した携帯型ゲーム機で、初代モデルのワンダースワンの後継機種です。従来のモノクロ液晶に加え、カラー液晶を採用し、画面表示の美しさが向上しました。また、初代モデルよりもCPUやRAMなどの性能も向上しており、より高精細なグラフィックスやサウンドが楽しめるようになりました。カラーバリエーションも豊富で、ボタンのデザインが異なる限定版なども発売されました。携帯性に優れたサイズ感やバッテリー駆動時間も改善され、様々なジャンルのゲームが発売され、特に「ロックマン&フォルテ」や「ファイナルファンタジー」シリーズなどが人気を博しました。', 'WSC', 'WSC', 8, 'PORTABLE', '2000-12-09', 35, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);
INSERT INTO `machines` (`id`, `name`, `kana`, `overview`, `code`, `abbreviation`, `manufacturer_id`, `machine_type`, `release_date`, `sort_order`, `created_at`, `updated_at`) VALUES (35, 'ニンテンドーゲームキューブ', 'ニンテンドーゲームキューブ', 'ゲームキューブは、任天堂が2001年に発売した家庭用ゲーム機です。小型・軽量な筐体や、遊び方によって形状を変えることができるコントローラーなど、独自のデザインが特徴的です。ディスクメディアには小型の光ディスクを採用し、高速な読み込みと高音質を実現しました。マリオやゼルダの伝説、メトロイドプライムなど、多彩なゲームソフトが発売され、高い評価を得ました。また、最大4人までのマルチプレイに対応しており、多人数でのプレイが可能でした。しかし、ライバル機種であるプレイステーション2やXboxに比べ、販売台数は伸び悩み、2007年に販売終了となりました。', 'GC', 'GC', 1, 'STATIONARY', '2001-09-14', 5, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP);